@code {
    private DateTime weekStart;
    private List<Appointment> weekAppointments = new();
    private List<Appointment> upcomingAppointments = new();
    private List<Pet> allPets = new();
    private bool showForm, hasConflict;
    private Appointment? editingAppointment;
    private int formPetId;
    private DateTime formStart = DateTime.Today.AddHours(9);
    private int formDuration = 30;
    private string formVet = "", formReason = "", formNotes = "", formError = "";

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        await LoadData();
    }

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);

        weekAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd && a.Status != AppointmentStatus.Cancelled)
            .ToListAsync();

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(20)
            .ToListAsync();

        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void PrevWeek() { weekStart = weekStart.AddDays(-7); _ = LoadData(); }
    private void NextWeek() { weekStart = weekStart.AddDays(7); _ = LoadData(); }
    private void GoToToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek); _ = LoadData(); }

    private void SelectSlot(DateTime slotTime)
    {
        editingAppointment = null;
        formStart = slotTime;
        formPetId = 0;
        formVet = "";
        formReason = "";
        formNotes = "";
        formError = "";
        hasConflict = false;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = apt;
        formPetId = apt.PetId;
        formStart = apt.StartTime;
        formDuration = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        formVet = apt.VeterinarianName;
        formReason = apt.Reason;
        formNotes = apt.Notes;
        formError = "";
        hasConflict = false;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        formError = "";
        if (formPetId == 0) { formError = "Please select a pet."; return; }
        if (string.IsNullOrWhiteSpace(formVet)) { formError = "Veterinarian name is required."; return; }
        if (string.IsNullOrWhiteSpace(formReason)) { formError = "Reason is required."; return; }

        var endTime = formStart.AddMinutes(formDuration);

        await using var db = await DbFactory.CreateDbContextAsync();
        var conflict = await db.Appointments
            .AnyAsync(a => a.Id != (editingAppointment?.Id ?? 0)
                && a.Status != AppointmentStatus.Cancelled
                && a.VeterinarianName == formVet
                && a.StartTime < endTime && a.EndTime > formStart);

        if (conflict) { hasConflict = true; return; }
        hasConflict = false;

        if (editingAppointment != null)
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = formPetId;
                apt.StartTime = formStart;
                apt.EndTime = endTime;
                apt.VeterinarianName = formVet;
                apt.Reason = formReason;
                apt.Notes = formNotes;
                await db.SaveChangesAsync();
            }
        }
        else
        {
            db.Appointments.Add(new Appointment
            {
                PetId = formPetId,
                StartTime = formStart,
                EndTime = endTime,
                VeterinarianName = formVet,
                Reason = formReason,
                Notes = formNotes,
                Status = AppointmentStatus.Scheduled
            });
            await db.SaveChangesAsync();
        }

        showForm = false;
        await LoadData();
    }

    private async Task CancelAppointment()
    {
        if (editingAppointment == null) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        var apt = await db.Appointments.FindAsync(editingAppointment.Id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        showForm = false;
        editingAppointment = null;
        await LoadData();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}
```

