@page "/"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Clinic Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@totalPets</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@totalOwners</p>
            </div>
        </div>
    </div>
</div>

<h3>Today's Schedule</h3>
@if (todaySchedule.Any())
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th></tr>
        </thead>
        <tbody>
            @foreach (var apt in todaySchedule)
            {
                <tr>
                    <td>@apt.StartTime.ToString("HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
                    <td>@apt.Pet.Name</td>
                    <td>@apt.Pet.Owner.LastName</td>
                    <td>@apt.Reason</td>
                    <td>@apt.VeterinarianName</td>
                    <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No appointments scheduled for today.</p>
}

@code {
    private int totalPets, todayAppointments, pendingInvoices, totalOwners;
    private List<Appointment> todaySchedule = new();

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);

        totalPets = await db.Pets.CountAsync();
        totalOwners = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled);
        pendingInvoices = await db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Issued);

        todaySchedule = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

