        else
        {
            <p class="text-muted">Select a patient or register a new one.</p>
        }
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Owner> owners = new();
    private Pet? selectedPet;
    private string searchTerm = "";
    private bool showNewPetForm, createNewOwner, editingPet;
    private Pet newPet = new();
    private Owner newOwner = new();
    private int selectedOwnerId;
    private DateTime? newPetDob;
    private TreatmentNote newNote = new();
    private string formError = "";

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    [CascadingParameter]
    private Task<AuthenticationState>? AuthState { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowNewPetForm()
    {
        showNewPetForm = true;
        selectedPet = null;
        newPet = new Pet();
        newOwner = new Owner();
        selectedOwnerId = 0;
        newPetDob = null;
        formError = "";
    }

    private async Task SaveNewPet()
    {
        formError = "";
        if (string.IsNullOrWhiteSpace(newPet.Name) || string.IsNullOrWhiteSpace(newPet.Species))
        {
            formError = "Pet name and species are required.";
            return;
        }

        await using var db = await DbFactory.CreateDbContextAsync();

        if (createNewOwner)
        {
            if (string.IsNullOrWhiteSpace(newOwner.FirstName) || string.IsNullOrWhiteSpace(newOwner.LastName))
            {
                formError = "Owner first and last name are required.";
                return;
            }
            db.Owners.Add(newOwner);
            await db.SaveChangesAsync();
            newPet.OwnerId = newOwner.Id;
        }
        else
        {
            if (selectedOwnerId == 0) { formError = "Please select an owner."; return; }
            newPet.OwnerId = selectedOwnerId;
        }

        if (newPetDob.HasValue) newPet.DateOfBirth = DateOnly.FromDateTime(newPetDob.Value);
        db.Pets.Add(newPet);
        await db.SaveChangesAsync();

        showNewPetForm = false;
        await LoadData();
    }

    private async Task SelectPet(Pet pet)
    {
        showNewPetForm = false;
        editingPet = false;
        await using var db = await DbFactory.CreateDbContextAsync();
        selectedPet = await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes)
            .FirstOrDefaultAsync(p => p.Id == pet.Id);
        newNote = new TreatmentNote();
    }

    private async Task SavePetEdit()
    {
        if (selectedPet == null) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Pets.Update(selectedPet);
        await db.SaveChangesAsync();
        editingPet = false;
        await LoadData();
    }

    private async Task AddTreatmentNote()
    {
        if (selectedPet == null || string.IsNullOrWhiteSpace(newNote.Description)) return;
        string staffName = "Staff";
        if (AuthState != null)
        {
            var authState = await AuthState;
            staffName = authState.User.Identity?.Name ?? "Unknown";
        }
        newNote.PetId = selectedPet.Id;
        newNote.StaffName = staffName;
        newNote.CreatedAt = DateTime.UtcNow;

        await using var db = await DbFactory.CreateDbContextAsync();
        db.TreatmentNotes.Add(newNote);
        await db.SaveChangesAsync();

        newNote = new TreatmentNote();
        selectedPet = await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes)
            .FirstOrDefaultAsync(p => p.Id == selectedPet.Id);
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row">
    <div class="col-md-8">
        <div class="d-flex mb-3 align-items-center">
            <button class="btn btn-outline-secondary btn-sm" @onclick="PrevWeek">&lt;</button>
            <h5 class="mx-3 mb-0">@weekStart.ToString("MMM dd") – @weekStart.AddDays(6).ToString("MMM dd, yyyy")</h5>
            <button class="btn btn-outline-secondary btn-sm" @onclick="NextWeek">&gt;</button>
            <button class="btn btn-outline-primary btn-sm ms-3" @onclick="GoToToday">Today</button>
        </div>

        <div class="table-responsive">
            <table class="table table-bordered table-sm">
                <thead>
                    <tr>
                        <th style="width:60px">Time</th>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            <th class="text-center @(day.Date == DateTime.Today ? "table-active" : "")">
                                @day.ToString("ddd")<br/>@day.ToString("MM/dd")
                            </th>
                        }
                    </tr>
                </thead>
                <tbody>
                    @for (int h = 8; h < 18; h++)
                    {
                        var hour = h;
                        <tr>
                            <td class="text-muted small">@($"{hour:00}:00")</td>
                            @for (int d = 0; d < 7; d++)
                            {
                                var slotTime = weekStart.AddDays(d).AddHours(hour);
                                var slotAppts = weekAppointments.Where(a => a.StartTime <= slotTime && a.EndTime > slotTime).ToList();
                                <td class="@(slotAppts.Any() ? "table-warning" : "")" style="cursor:pointer; font-size:0.8em;"
                                    @onclick="() => SelectSlot(slotTime)">
                                    @foreach (var a in slotAppts)
                                    {
                                        <div class="badge bg-@GetStatusColor(a.Status) text-truncate d-block mb-1" style="max-width:100px;" title="@a.Pet.Name - @a.Reason">
                                            @a.Pet.Name
                                        </div>
                                    }
                                </td>
                            }
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <div class="col-md-4">
        @if (showForm)
        {
            <div class="card">
                <div class="card-header">@(editingAppointment != null ? "Edit Appointment" : "New Appointment")</div>
                <div class="card-body">
                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="formPetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in allPets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date &amp; Time</label>
                        <input type="datetime-local" class="form-control" @bind="formStart" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration (minutes)</label>
                        <select class="form-select" @bind="formDuration">
                            <option value="30">30 min</option>
                            <option value="60">60 min</option>
                            <option value="90">90 min</option>
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Veterinarian</label>
                        <input class="form-control" @bind="formVet" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reason</label>
                        <input class="form-control" @bind="formReason" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <textarea class="form-control" rows="2" @bind="formNotes"></textarea>
                    </div>

                    @if (hasConflict)
                    {
                        <div class="alert alert-danger">Time slot conflicts with an existing appointment.</div>
                    }

                    <button class="btn btn-success me-2" @onclick="SaveAppointment">Save</button>
                    @if (editingAppointment != null)
                    {
                        <button class="btn btn-danger me-2" @onclick="CancelAppointment">Cancel Appt</button>
                    }
                    <button class="btn btn-secondary" @onclick="() => showForm = false">Close</button>

                    @if (!string.IsNullOrEmpty(formError))
                    {
                        <div class="alert alert-danger mt-2">@formError</div>
                    }
                </div>
            </div>
        }
        else
        {
            <div class="card">
                <div class="card-header">Upcoming Appointments</div>
                <div class="card-body p-0">
                    <div class="list-group list-group-flush" style="max-height:60vh; overflow-y:auto;">
                        @foreach (var apt in upcomingAppointments)
                        {
                            <button class="list-group-item list-group-item-action" @onclick="() => EditAppointment(apt)">
                                <div class="d-flex justify-content-between">
                                    <strong>@apt.Pet.Name</strong>
                                    <span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span>
                                </div>
                                <small>@apt.StartTime.ToString("g") — @apt.VeterinarianName</small><br/>
                                <small class="text-muted">@apt.Reason</small>
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private DateTime weekStart;
    private List<Appointment> weekAppointments = new();
    private List<Appointment> upcomingAppointments = new();
    private List<Pet> allPets = new();
    private bool showForm, hasConflict;
    private Appointment? editingAppointment;
    private int formPetId;
    private DateTime formStart = DateTime.Today.AddHours(9);
    private int formDuration = 30;
    private string formVet = "", formReason = "", formNotes = "", formError = "";

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        await LoadData();
    }

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);

        weekAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd && a.Status != AppointmentStatus.Cancelled)
            .ToListAsync();

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(20)
            .ToListAsync();

        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task PrevWeek() { weekStart = weekStart.AddDays(-7); await LoadData(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadData(); }
    private async Task GoToToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek); await LoadData(); }

    private void SelectSlot(DateTime slotTime)
    {
        editingAppointment = null;
        formStart = slotTime;
        formPetId = 0;
        formVet = "";
        formReason = "";
        formNotes = "";
        formError = "";
        hasConflict = false;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = apt;
        formPetId = apt.PetId;
        formStart = apt.StartTime;
        formDuration = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        formVet = apt.VeterinarianName;
        formReason = apt.Reason;
        formNotes = apt.Notes;
        formError = "";
        hasConflict = false;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        formError = "";
        if (formPetId == 0) { formError = "Please select a pet."; return; }
        if (string.IsNullOrWhiteSpace(formVet)) { formError = "Veterinarian name is required."; return; }
        if (string.IsNullOrWhiteSpace(formReason)) { formError = "Reason is required."; return; }

        var endTime = formStart.AddMinutes(formDuration);

        await using var db = await DbFactory.CreateDbContextAsync();
        var conflict = await db.Appointments
            .AnyAsync(a => a.Id != (editingAppointment?.Id ?? 0)
                && a.Status != AppointmentStatus.Cancelled
                && a.VeterinarianName == formVet
                && a.StartTime < endTime && a.EndTime > formStart);

        if (conflict) { hasConflict = true; return; }
        hasConflict = false;

        if (editingAppointment != null)
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = formPetId;
                apt.StartTime = formStart;
                apt.EndTime = endTime;
                apt.VeterinarianName = formVet;
                apt.Reason = formReason;
                apt.Notes = formNotes;
                await db.SaveChangesAsync();
            }
        }
        else
        {
            db.Appointments.Add(new Appointment
            {
                PetId = formPetId,
                StartTime = formStart,
                EndTime = endTime,
                VeterinarianName = formVet,
                Reason = formReason,
                Notes = formNotes,
                Status = AppointmentStatus.Scheduled
            });
            await db.SaveChangesAsync();
        }

        showForm = false;
        await LoadData();
    }

    private async Task CancelAppointment()
    {
        if (editingAppointment == null) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        var apt = await db.Appointments.FindAsync(editingAppointment.Id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        showForm = false;
        editingAppointment = null;
        await LoadData();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/billing"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing &amp; Payments</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item"><button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button></li>
    <li class="nav-item"><button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button></li>
    <li class="nav-item"><button class="nav-link @(activeTab == "new" ? "active" : "")" @onclick="ShowNewInvoice">+ New Invoice</button></li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <select class="form-select d-inline-block w-auto" @bind="statusFilter">
            <option value="">All Statuses</option>
            <option value="Draft">Draft</option>
            <option value="Issued">Issued</option>
            <option value="Paid">Paid</option>
            <option value="Void">Void</option>
        </select>
    </div>

    <table class="table table-striped">
        <thead>
            <tr><th>#</th><th>Date</th><th>Pet</th><th>Description</th><th>Amount</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in FilteredInvoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.IssuedAt.ToString("yyyy-MM-dd")</td>
                    <td>@inv.Appointment.Pet.Name</td>
                    <td>@inv.Description</td>
                    <td>$@inv.Amount.ToString("F2")</td>
                    <td><span class="badge bg-@GetInvoiceColor(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status == InvoiceStatus.Draft)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => IssueInvoice(inv)">Issue</button>
                        }
                        @if (inv.Status == InvoiceStatus.Issued)
                        {
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => ShowPaymentForm(inv)">Pay</button>
                        }
                        @if (inv.Status is InvoiceStatus.Draft or InvoiceStatus.Issued)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => VoidInvoice(inv)">Void</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}
else if (activeTab == "payments")
{
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Pet</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var pay in payments)
            {
                <tr>
                    <td>@pay.PaidAt.ToString("g")</td>
                    <td>@pay.InvoiceId</td>
                    <td>@pay.Invoice.Appointment.Pet.Name</td>
                    <td>$@pay.Amount.ToString("F2")</td>
                    <td>@pay.Method</td>
                    <td>@pay.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}
else if (activeTab == "new")
{
    <div class="card" style="max-width:600px;">
        <div class="card-header">Generate Invoice</div>
        <div class="card-body">
            <div class="mb-2">
                <label class="form-label">Appointment</label>
                <select class="form-select" @bind="newInvAppointmentId">
                    <option value="0">-- Select Completed Appointment --</option>
                    @foreach (var a in uninvoicedAppointments)
                    {
                        <option value="@a.Id">@a.StartTime.ToString("MM/dd HH:mm") — @a.Pet.Name (@a.Reason)</option>
                    }
                </select>
            </div>
            <div class="mb-2">
                <label class="form-label">Amount ($)</label>
                <input type="number" step="0.01" class="form-control" @bind="newInvAmount" />
            </div>
            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="newInvDescription"></textarea>
            </div>
            <button class="btn btn-success" @onclick="CreateInvoice">Create Invoice</button>
            @if (!string.IsNullOrEmpty(invoiceError))
            {
                <div class="alert alert-danger mt-2">@invoiceError</div>
            }
        </div>
    </div>
}

@if (showPayment)
{
    <div class="modal d-block" tabindex="-1" style="background:rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Process Payment — Invoice #@payingInvoice?.Id</h5>
                    <button type="button" class="btn-close" @onclick="() => showPayment = false"></button>
                </div>
                <div class="modal-body">
                    <p>Outstanding: <strong>$@GetOutstanding(payingInvoice!).ToString("F2")</strong></p>
                    <div class="mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control" @bind="payAmount" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="payMethod">
                            <option value="Cash">Cash</option>
                            <option value="Card">Card</option>
                            <option value="BankTransfer">Bank Transfer</option>
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reference</label>
                        <input class="form-control" @bind="payReference" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-primary" @onclick="ProcessPayment">Submit Payment</button>
                    <button class="btn btn-secondary" @onclick="() => showPayment = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string statusFilter = "";
    private List<Invoice> invoices = new();
    private List<Payment> payments = new();
    private List<Appointment> uninvoicedAppointments = new();

    private int newInvAppointmentId;
    private decimal newInvAmount;
    private string newInvDescription = "", invoiceError = "";

    private bool showPayment;
    private Invoice? payingInvoice;
    private decimal payAmount;
    private string payMethod = "Cash", payReference = "";

    private IEnumerable<Invoice> FilteredInvoices => string.IsNullOrEmpty(statusFilter)
        ? invoices
        : invoices.Where(i => i.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedAt)
            .ToListAsync();

        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Appointment).ThenInclude(a => a.Pet)
            .OrderByDescending(p => p.PaidAt)
            .ToListAsync();

        uninvoicedAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.Status == AppointmentStatus.Completed && a.Invoice == null)
            .OrderByDescending(a => a.StartTime)
            .ToListAsync();
    }

    private async Task ShowNewInvoice()
    {
        activeTab = "new";
        newInvAppointmentId = 0;
        newInvAmount = 0;
        newInvDescription = "";
        invoiceError = "";
        await LoadData();
    }

    private async Task CreateInvoice()
    {
        invoiceError = "";
        if (newInvAppointmentId == 0) { invoiceError = "Select an appointment."; return; }
        if (newInvAmount <= 0) { invoiceError = "Amount must be positive."; return; }

        await using var db = await DbFactory.CreateDbContextAsync();
        db.Invoices.Add(new Invoice
        {
            AppointmentId = newInvAppointmentId,
            Amount = newInvAmount,
            Description = newInvDescription,
            Status = InvoiceStatus.Draft,
            IssuedAt = DateTime.UtcNow
        });
        await db.SaveChangesAsync();
        activeTab = "invoices";
        await LoadData();
    }

    private async Task IssueInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Invoices.FindAsync(inv.Id);
        if (entity != null) { entity.Status = InvoiceStatus.Issued; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task VoidInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Invoices.FindAsync(inv.Id);
        if (entity != null) { entity.Status = InvoiceStatus.Void; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        payingInvoice = inv;
        payAmount = GetOutstanding(inv);
        payMethod = "Cash";
        payReference = "";
        showPayment = true;
    }

    private decimal GetOutstanding(Invoice inv) => inv.Amount - inv.Payments.Sum(p => p.Amount);

    private async Task ProcessPayment()
    {
        if (payingInvoice == null || payAmount <= 0) return;

        await using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = payAmount,
            Method = Enum.Parse<PaymentMethod>(payMethod),
            Reference = payReference,
            PaidAt = DateTime.UtcNow
        });

        var inv = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == payingInvoice.Id);
        if (inv.Payments.Sum(p => p.Amount) + payAmount >= inv.Amount)
        {
            inv.Status = InvoiceStatus.Paid;
        }
        await db.SaveChangesAsync();

        showPayment = false;
        await LoadData();
    }

    private string GetInvoiceColor(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Issued => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Void => "danger",
        _ => "light"
    };
}

